.someday-maybe {
  padding-block-start: var(--space-lg);
}

.someday-maybe h1 {
  margin-block-end: var(--space-lg);
}

.someday-maybe__error {
  background-color: var(--color-danger-light);
  color: var(--color-danger);
  padding: var(--space-sm) var(--space-md);
  border-radius: var(--radius-md);
  font-size: var(--font-size-sm);
  margin-block-end: var(--space-md);
}

/* Add someday/maybe form */
.someday-maybe__add {
  margin-block-end: var(--space-lg);
}

.someday-maybe__add-fields {
  display: flex;
  flex-direction: column;
  gap: var(--space-sm);
}

.someday-maybe__add-row {
  display: flex;
  gap: var(--space-sm);
}

.someday-maybe__add-input {
  flex: 1;
  min-inline-size: 8rem;
}

.someday-maybe__add-submit {
  flex-shrink: 0;
}

/* Someday/maybe item list */
.someday-maybe__list {
  display: flex;
  flex-direction: column;
}

.someday-maybe-item {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: var(--space-sm);
  padding-block: var(--space-sm);
  padding-inline: var(--space-sm);
  border-block-end: 1px solid var(--color-border);
}

.someday-maybe-item:first-child {
  border-block-start: 1px solid var(--color-border);
}

.someday-maybe-item__content {
  flex: 1;
  min-inline-size: 0;
}

.someday-maybe-item__title {
  overflow-wrap: break-word;
}

.someday-maybe-item__date {
  flex-shrink: 0;
  font-size: var(--font-size-xs);
  color: var(--color-fg-subtle);
}

.someday-maybe-item__edit {
  color: var(--color-fg-muted);
  font-size: var(--font-size-sm);
  text-decoration: none;
  flex-shrink: 0;
}

.someday-maybe-item__edit:hover {
  color: var(--color-primary);
  text-decoration: underline;
}

